import React, { useEffect, useRef, useState } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { ProgressIndicatorCircular } from '@andes/progress-indicator-circular';
import { VisuallyHidden } from '@andes/visually-hidden';
import warning from '@andes/common/build/utils/warning';
import { namespace } from './constants';
import { useId } from '@andes/context';
import { useThemeContext } from '@andes/themes';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';
import { computeHierarchy } from './utils/computeHierarchy';

const progressIndicatorSize = {
  small: 'xsmall',
  medium: 'xsmall',
  large: 'small',
};

/**
 * Button text component
 * Utility component only to be used when Button content
 * includes more than just text (could be an icon or spinner)
 *
 * @type {typeof import('../index').ButtonText}
 */
const ButtonText = ({ children }) => <span className={`${namespace}__text`} data-andes-button-text>{children}</span>;

ButtonText.propTypes = {
  children: PropTypes.node.isRequired,
};

/** @type {typeof import('..').Button} */
const Button = (props) => {
  const {
    children,
    className,
    disabled = false,
    fullWidth = false,
    hierarchy = 'loud',
    href,
    id,
    loading,
    onClick,
    size = 'large',
    srAnnouncement,
    srLabel,
    type = 'button',
    ref,
    backgroundType = 'default',
    'data-andes-state': dataAndesState,
    ...otherProps
  } = props;

  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  /** @type {React.RefObject<NodeJS.Timeout | undefined>} */
  const srLabelTimeout = useRef(undefined);
  const firstRender = useRef(true);

  const [srAnnouncementLabel, setSrAnnouncementLabel] = useState('');
  const [loadingComplete, setLoadingComplete] = useState(false);

  const computedHierarchy = computeHierarchy(hierarchy);

  // Resets label when the component finishes loading
  useEffect(() => {
    if (!loading) {
      setSrAnnouncementLabel('');

      if (!firstRender.current) setLoadingComplete(true);
    }

    if (firstRender) firstRender.current = false;
  }, [loading]);

  useEffect(() => {
    /** @type {NodeJS.Timeout} */
    let finishTimeout;
    if (loadingComplete) {
      finishTimeout = setTimeout(() => {
        setLoadingComplete(false);
        /**
         * The exit animation takes 0.2 seconds to avoid animation failures it must be the same value.
         * TODO: When supported by more browsers I will change this implementation to animationend to be more precise.
         * https://caniuse.com/?search=animationend
         */
      }, 200);
    }

    return () => clearTimeout(finishTimeout);
  }, [loadingComplete]);

  useEffect(() => () => {
    clearTimeout(srLabelTimeout.current);
  }, []);

  warning(
    !loading || (loading && srAnnouncement),
    `<ButtonWithSpinner> needs some plain text contents for accessibility reasons.
    Please add a 'srAnnouncement' prop.`,
  );

  const classes = classNames(namespace, className, {
    [`${namespace}--${size}`]: size,
    [`${namespace}--${computedHierarchy}`]: computedHierarchy,
    [`${namespace}--disabled`]: disabled,
    [`${namespace}--full-width`]: fullWidth,
    [`${namespace}--loading`]: loading,
    [`${namespace}--loading-complete`]: loadingComplete,
    [`${namespace}--color-on-background`]: backgroundType === 'complexBackground',
  },
  getThemedComponentClasses?.('button'));

  const sharedProps = {
    className: classes,
    id: componentId,
    'aria-label': srLabel,
    ...otherProps,
    'data-andes-button': true,
    'data-andes-button-hierarchy': computedHierarchy,
    'data-andes-button-size': size,
    ...computeDataAndesState({
      // eslint-disable-next-line react/prop-types
      ...(dataAndesState ? { otherDataAndesState: dataAndesState } : {}),
      disabled,
      loading,
    }),
    ...themeHash,
  };

  const content = <span className={`${namespace}__content`} data-andes-button-content>{children}</span>;

  if (href) {
    /** @type {React.AnchorHTMLAttributes<HTMLAnchorElement> & React.RefAttributes<HTMLAnchorElement | null>} */
    const anchorProps = {
      ...((disabled || loading) ? {
        role: 'link',
        'aria-disabled': true,
      } : {
        href,
      }),
      // eslint-disable-next-line object-shorthand
      ref: /** @type {React.RefObject<HTMLAnchorElement | null>} */ (/** @type {unknown} */ (ref)),
      // eslint-disable-next-line object-shorthand
      onClick: /** @type {React.MouseEventHandler<HTMLAnchorElement>} */ (/** @type {unknown} */(onClick)),
      ...sharedProps,
    };

    return (
      <a {...anchorProps}>
        {content}
      </a>
    );
  }

  /** @type {React.ButtonHTMLAttributes<HTMLButtonElement> & React.RefAttributes<HTMLButtonElement | null>} */
  const buttonProps = {
    disabled: disabled || loading,
    // eslint-disable-next-line object-shorthand
    ref: /** @type {React.RefObject<HTMLButtonElement | null>} */ (/** @type {unknown} */ (ref)),
    // eslint-disable-next-line object-shorthand
    type: /** @type {React.ButtonHTMLAttributes<HTMLButtonElement>['type']} */ (type),
    ...sharedProps,
  };

  /** @type {React.MouseEventHandler<HTMLButtonElement>} */
  const customOnClick = (event) => {
    const label = srAnnouncement || '';
    srLabelTimeout.current = setTimeout(() => setSrAnnouncementLabel(label), 30);

    if (typeof onClick === 'function') onClick(event);
  };

  const progressSize = /** @type {'small' | 'medium' | 'large'} */ (progressIndicatorSize[size]);

  return (
    <>
      <button {...buttonProps} onClick={customOnClick}>
        {content}
        {loading && (
          <ProgressIndicatorCircular
             // @ts-expect-error It is a prop for internal use and is not typed.
            ariaLabelledBy={componentId}
            size={progressSize}
          />
        )}
      </button>
      {loading && <VisuallyHidden aria-live="assertive">{srAnnouncementLabel}</VisuallyHidden>}
    </>
  );
};

Button.displayName = 'Button';

Button.propTypes = {
  backgroundType: PropTypes.oneOf(['default', 'complexBackground']),
  children: PropTypes.node.isRequired,
  className: PropTypes.string,
  disabled: PropTypes.bool,
  fullWidth: PropTypes.bool,
  hierarchy: PropTypes.oneOf(['loud', 'quiet', 'mute']),
  href: PropTypes.string,
  id: PropTypes.string,
  loading: PropTypes.bool,
  onClick: PropTypes.func,
  size: PropTypes.oneOf(['small', 'medium', 'large']),
  srAnnouncement: PropTypes.string,
  srLabel: PropTypes.string,
  type: PropTypes.string,
};

export {
  Button as default,
  ButtonText,
};
