import React, { useState, useEffect, useRef } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import Button from './Button';
import { useId } from '@andes/context';
import { VisuallyHidden } from '@andes/visually-hidden';
import warning from '@andes/common/build/utils/warning';
import { WARNING_A11Y_PROGRESS_LABEL } from './constants/warning';

const STATES = {
  LOADING: 'loading',
  ENTERED: 'entered',
  FINISHED: 'finished',
};
const DEFAULT_HIERARCHY = 'loud';
const HIERARCHY_ALLOWED = {
  [DEFAULT_HIERARCHY]: true,
  quiet: true,
};

/**
 * @param {string[]} stages
 * @param {Record<string, unknown>} defaultClasses
 */
const buildClassesObject = (stages, defaultClasses = {}) => stages.reduce(
  (classes, stage) => ({ ...classes, [stage]: true }),
  defaultClasses,
);

/** @type {typeof import('..').ProgressButton} */
const ProgressButton = ({
  children,
  className,
  disabled,
  hierarchy = 'loud',
  id,
  loading = false,
  progressLabel,
  progressSrAnnouncement,
  timeout = 1000,
  ref,
  ...otherProps
}) => {
  const componentId = useId(id);
  const mounted = useRef(false);
  const [stages, setStages] = useState([STATES.ENTERED]);
  const hierarchySelected = HIERARCHY_ALLOWED[hierarchy]
    ? hierarchy
    : DEFAULT_HIERARCHY;

  warning(Boolean(progressLabel || progressSrAnnouncement), WARNING_A11Y_PROGRESS_LABEL);

  useEffect(() => {
    if (mounted.current) {
      if (loading) {
        setStages([STATES.LOADING]);
      } else {
        setStages([STATES.LOADING, STATES.FINISHED]);
        const finishTimeout = setTimeout(() => {
          setStages([STATES.FINISHED]);
        }, timeout);

        return () => clearTimeout(finishTimeout);
      }
    }
  }, [loading, timeout]);

  useEffect(() => {
    mounted.current = true;
    if (loading) {
      setStages([STATES.LOADING]);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const classObject = buildClassesObject(stages, {
    'andes-button--progress__label': Boolean(progressLabel),
  });
  const classes = classNames('andes-button--progress', className, classObject);

  return (
    <>
      <Button
        id={componentId}
        hierarchy={hierarchySelected}
        className={classes}
        ref={ref}
        disabled={disabled || loading}
        {...otherProps}
        {...loading ? { 'data-andes-state': 'progress' } : {}}
      >
        {(progressLabel && loading) ? (
          <span className="andes-button--progress__content">{progressLabel}</span>
        ) : children}
      </Button>
      <VisuallyHidden aria-live="assertive">{((progressSrAnnouncement || progressLabel) && loading)
        ? (progressSrAnnouncement || progressLabel) : ''}
      </VisuallyHidden>
    </>
  );
};

ProgressButton.propTypes = {
  children: PropTypes.node,
  className: PropTypes.string,
  disabled: PropTypes.bool,
  hierarchy: PropTypes.oneOf([
    'quiet',
    'loud',
  ]),
  id: PropTypes.string,
  loading: PropTypes.bool,
  progressLabel: PropTypes.node,
  progressSrAnnouncement: PropTypes.string,
  timeout: PropTypes.number,
};

ProgressButton.displayName = 'ProgressButton';

export default ProgressButton;
